package day1;

public class Program2_DataypeExample {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		//boolean takes 1 bit
boolean result = false;
System.out.println(result);
//byte takes 8 bits
//-128 to 129
byte ans = -128;
System.out.println(ans);
//short takes 2 bytes
//-32000 to 32000
short data = -32000;
System.out.println(data);
//char takes 2 byte
char alpha = 'a';
System.out.println(alpha);
 //8 bytes
long phoneNumber =9841256874l;
System.out.println(phoneNumber);
//float 4 bytes
//7 floating points
float marks3 =9.12345678F;
System.out.println(marks3);
float marks4 =91.2345678F;
System.out.println(marks4);
float marks5 =912.345678F;
System.out.println(marks5);
float marks6 =9123.45678F;
System.out.println(marks6);
double data_d = 9.12345678901234;
System.out.println(data_d);




	}

}
